sys_script_include.script:
var PayloadSizeCalculator = Class.create();
PayloadSizeCalculator.prototype = {
    initialize: function() {},

    calculateSizes: function(requestPayload, responsePayload) {
        return {
            requestBytes: this._getByteSize(requestPayload),
            responseBytes: this._getByteSize(responsePayload),
            totalBytes: this._getByteSize(requestPayload) + this._getByteSize(responsePayload)
        };
    },

    _getByteSize: function(str) {
        if (!str) return 0;

        var byteSize = 0;
        for (var i = 0; i < str.length; i++) {
            var code = str.charCodeAt(i);
            if (code < 0x80) {
                byteSize += 1;
            } else if (code < 0x800) {
                byteSize += 2;
            } else if (code < 0xD800 || code >= 0xE000) {
                byteSize += 3;
            } else {
                i++;
                byteSize += 4;
            }
        }
        return byteSize;
    },

    // Accurate UTF-8 byte measurement - calculates bytes based on each character's code point
    // Use this if the payload may contain non-ASCII characters (e.g. accented names like å, ä, ö)
    _getByteSize_UTF8(str) {
        if (!str) return 0;
        var byteSize = 0;
        for (var i = 0; i < str.length; i++) {
            var code = str.charCodeAt(i);
            if (code < 0x80) byteSize += 1;
            else if (code < 0x800) byteSize += 2;
            else if (code < 0xd800 || code >= 0xe000) byteSize += 3;
            else {
                i++;
                byteSize += 4;
            }
        }
        return byteSize;
    },

    // Approximate UTF-8 byte measurement - only accurate for purely ASCII payloads
    // For ASCII characters UTF-8 byte count equals character count, so .length is sufficient
    // Non-ASCII characters (e.g. å, ä, ö) will be underestimated as they occupy 2 bytes in UTF-8
    _getByteSize_ASCII_only(str) {
        if (!str) return 0;
        return str.length;
    },

    // UTF-16 byte measurement - only relevant if both sides communicate in UTF-16
    // Do NOT use for REST APIs - HTTP standard defaults to UTF-8
    _getByteSize_UTF16(str) {
        if (!str) return 0;
        return str.length * 2;
    },

    type: 'PayloadSizeCalculator'
};
